import React, { useEffect, useState } from "react";
import API from "../Api/axios";

const ProductsCard = ({ logout, addToCart }) => {
  const [products, setProducts] = useState([]);
  const [added, setAdded] = useState({});

  const fetchProducts = async () => {
    try {
      const res = await API.get("/products");
      setProducts(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  const backendBase = API.defaults.baseURL.replace("/api", "");

  const saveProduct = async (product) => {
    // add to client-side cart
    try {
      addToCart(product);
      setAdded((s) => ({ ...s, [product._id]: true }));
      setTimeout(() => setAdded((s) => ({ ...s, [product._id]: false })), 900);
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Products</h2>


      <div style={{ display: "flex", gap: 16, flexWrap: "wrap", marginTop: 16 }}>
        {products.map((p) => (
          <div key={p._id} style={{ border: "1px solid #ddd", padding: 12, width: 220 }}>
            {p.image && (
              <img src={p.image.startsWith("/") ? backendBase + p.image : p.image} alt={p.name} style={{ width: "100%", height: 120, objectFit: "cover" }} />
            )}

            <h4>{p.name}</h4>
            <p>₹{p.price}</p>
            {p.info && <p style={{ fontSize: 13 }}>{p.info}</p>}

            <button onClick={() => saveProduct(p)}>{added[p._id] ? "Added" : "Add to Cart"}</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ProductsCard;
